select * from gb_department_orders_history


		and gb_DOH_dep_dis_goods_id = #{depDisGoodsId}


		and gb_DOH_department_id = #{depId}


order by gb_department_orders_history_id

select * from gb_department_orders_history


		and gb_DOH_dep_dis_goods_id = #{depDisGoodsId}


		and gb_DOH_department_id = #{depId}


order by gb_department_orders_history_id

SELECT gb_DOH_dis_goods_id AS goodsId, SUM(gb_DOH_quantity) / #{days} AS avgDailyQty FROM gb_department_orders_history WHERE gb_DOH_department_id = #{depId} AND gb_DOH_dis_goods_id IN
#{gid}
AND gb_DOH_apply_date >= CURDATE() - INTERVAL #{days} DAY GROUP BY gb_DOH_dis_goods_id

SELECT t.nxDohDisGoodsId AS nxDohDisGoodsId, t.nxDohQuantity AS nxDohQuantity, t.nxDohApplyDate AS nxDohApplyDate FROM ( SELECT gb_DOH_dis_goods_id AS nxDohDisGoodsId, gb_DOH_quantity AS nxDohQuantity, gb_DOH_apply_date AS nxDohApplyDate, ROW_NUMBER() OVER ( PARTITION BY gb_DOH_dis_goods_id ORDER BY gb_DOH_apply_date DESC ) AS rn FROM gb_department_orders_history WHERE gb_DOH_department_id = #{depId} AND gb_DOH_dis_goods_id IN
#{gid}
) t WHERE t.rn = 1
